<dir table="hrtttcd" code="nam, ky, dot, stt_rec, ma_tc, ngay_tu" order="nam, ky, dot, ma_nv, ma_tc, ngay_tu" xmlns="urn:schemas-fast-com:data-dir">
  <title v="danh sách lao động phát sinh thanh toán theo chế độ" e="Data Entry for Social Insurance Benefits"></title>

  <fields>
    <field name="stt_rec" isPrimaryKey="true" hidden="true">
      <header v="" e=""></header>
    </field>

    <field name="dot" isPrimaryKey="true" type="Decimal" clientDefault="Default" defaultValue="1" dataFormatString="#0" allowNulls="false">
      <header v="Đợt" e="Time"></header>
      <items style="Numeric"/>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="ky" isPrimaryKey="true" type="Decimal" dataFormatString="#0" readOnly="true">
      <header v="Tháng" e="Month"></header>
      <items style="Numeric"/>
    </field>
    <field name="nam" isPrimaryKey="true" type="Decimal" dataFormatString="###0" readOnly="true">
      <header v="Năm" e="Year"></header>
      <items style="Numeric"/>
    </field>
    <field name="ma_nv" allowNulls="false" external="true" defaultValue="''" allowContain="true">
      <header v="Mã nhân viên" e="Employee ID"></header>
      <items style="AutoComplete" controller="hrEmployee" reference="ho_ten" key="(@@admin = 1 or bo_phan in (select a.ma_bp from hrbp a, @@sysDatabaseName..hrquyenbp b where dbo.ff_Inlist(a.bp_ref, b.r_access2) = 1 and b.user_id = @@userID)) and status = '1'" check="@@admin = 1 or bo_phan in (select a.ma_bp from hrbp a, @@sysDatabaseName..hrquyenbp b where dbo.ff_Inlist(a.bp_ref, b.r_access2) = 1 and b.user_id = @@userID)" information="ma_nv$vhrnv.ten"/>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="ho_ten" readOnly="true" external="true" defaultValue="''">
      <header v="" e=""></header>
    </field>

    <field name="ma_tc" isPrimaryKey="true" allowNulls="false" allowContain="true">
      <header v="Mã trợ cấp" e="Benefit Code"></header>
      <items style="AutoComplete" controller ="hrSIBenefitItem" key="status = 1" check="1 = 1" reference="ten_tcbh%l" information="ma_tcbh$hrdmtcbh.ten_tcbh%l"></items>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="ten_tcbh%l" readOnly="true" external="true" defaultValue="''">
      <header v="" e=""></header>
    </field>

    <field name="loai_tc" allowContain="true">
      <header v="Kiểu trợ cấp" e="Benefit Category"></header>
      <items style="AutoComplete" controller ="hrSIBenefitType" key="status = 1 and ma_tcbh = '{$%c[ma_tc]}'" check="ma_tcbh = '{$%c[ma_tc]}'" reference="ten_kieu%l" information="ma_kieu$hrdmktcbh.ten_kieu%l"></items>
    </field>
    <field name="ten_kieu%l" readOnly="true" external="true" defaultValue="''">
      <header v="" e=""></header>
    </field>

    <field name="thang_lk" readOnly="true" external="true" type="Decimal" dataFormatString="#0" defaultValue="0">
      <header v="" e=""></header>
      <items style="Numeric"/>
    </field>
    <field name="ty_le" readOnly="true" external="true" type="Decimal" dataFormatString="#0.00" defaultValue="0">
      <header v="" e=""></header>
      <items style="Numeric"/>
    </field>
    <field name="t_so_ngay" readOnly="true" external="true" type="Decimal" dataFormatString="#0" defaultValue="0">
      <header v="" e=""></header>
      <items style="Numeric"/>
    </field>
    <field name="so_ngay_00" readOnly="true" external="true" type="Decimal" dataFormatString="#0" defaultValue="0">
      <header v="" e=""></header>
      <items style="Numeric"/>
    </field>
    <field name="luong_tt" readOnly="true" external="true" type="Decimal" dataFormatString="@generalCurrencyAmountInputFormat" defaultValue="0">
      <header v="" e=""></header>
      <items style="Numeric"/>
    </field>
    <field name="so_thang_ltt" readOnly="true" external="true" type="Decimal" dataFormatString="#0" defaultValue="0">
      <header v="" e=""></header>
      <items style="Numeric"/>
    </field>

    <field name="tg_bhxh" clientDefault="00-00" readOnly="true">
      <header v="Thời gian đóng BHXH" e="SI Paying Duration"></header>
      <footer v="(Năm-Tháng)" e="(YY-MM)"></footer>
    </field>
    <field name="nam_bhxh" type="Decimal" dataFormatString="#0" external="true" defaultValue="0" allowContain="true">
      <header v="" e=""></header>
      <items style="Numeric"/>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="thang_bhxh" type="Decimal" dataFormatString="#0" external="true" defaultValue="0" allowContain="true">
      <header v="" e=""></header>
      <items style="Numeric"/>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="tt_bhxh">
      <header v="Tình trạng" e="Benefit Status"></header>
    </field>
    <field name="td_bhxh">
      <header v="Thời điểm" e="Benefit Time"></header>
    </field>
    <field name="dk_muc_huong">
      <header v="Điều kiện, mức hưởng" e="Enjoyed Level / Criteria"></header>
    </field>

    <field name="ngay_tu" isPrimaryKey="true" type="DateTime" dataFormatString="@datetimeFormat" allowNulls="false">
      <header v="Từ ngày" e="Date from"></header>
      <footer v="Ngày từ/đến" e="Date from/to"></footer>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="ngay_den" type="DateTime" dataFormatString="@datetimeFormat" allowNulls="false">
      <header v="Đến ngày" e="Date to"></header>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="ngay_sinh_con" type="DateTime" dataFormatString="@datetimeFormat">
      <header v="Sinh/nhận con nuôi" e="Childbirth/Adoption"></header>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="so_ngay" type="Decimal" dataFormatString="##0.00" align ="right">
      <header v="Tổng số ngày" e="No. of Day(s)"></header>
      <items style="Numeric"/>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="tt_thang" type="Boolean" defaultValue="0">
      <header v="Tính theo tháng" e="Calculate by Month"></header>
      <clientScript><![CDATA[<Encrypted>&96EB7KSJ4WpQv9tz7CWyJfpQdpXBoeDYAu2NtnpqKkZizXrOin+ThlBb1Cud69GEKhMQG/e6ACHRw6lnJ7bb7gv7ENU78dJFsS5F8sl0AsZrdi4VuqiDAjUszXjbC8vo</Encrypted>]]></clientScript>
    </field>
    <field name="so_thang" type="Decimal" dataFormatString="#0">
      <header v="Số tháng" e="No. of Months"></header>
      <items style="Numeric"/>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="lk_dau_nam" type="Decimal" dataFormatString="### ##0.00" align ="right">
      <header v="Lũy kế từ đầu năm" e="YTD Accumulation"></header>
      <items style="Numeric"/>
    </field>
    <field name="tien_bhxh" type="Decimal" dataFormatString="@generalCurrencyAmountInputFormat" align ="right">
      <header v="Tiền lương" e="Base Salary"></header>
      <items style="Numeric"/>
      <clientScript><![CDATA[<Encrypted>&zklrcJcvTWecGhoNwtU99I331cUSBHb48Um6/MIxKF1XV6h6gBP5Nrw7p4fZnjgbKOT9v1M4nHnNHV9jdvwNVy0xEEldTcz4PzsMr9oZ+xw=</Encrypted>]]></clientScript>
    </field>
    <field name="st_tc_tk" type="Decimal" dataFormatString="@generalCurrencyAmountInputFormat" align ="right">
      <header v="Trợ cấp trong kỳ" e="Benefit Amount"></header>
      <items style="Numeric"/>
    </field>
    <field name="ht_tc" clientDefault="Default">
      <header v="Hình thức nhận trợ cấp" e="Form of receiving"></header>
    </field>
    <field name="tk_nhan_tc">
      <header v="Tài khoản nhận trợ cấp" e="Beneficiary Account"></header>
    </field>
    <field name="ghi_chu">
      <header v="Ghi chú" e="Note"></header>
    </field>
  </fields>

